<?php
$pageTitle='Marketplace Sync';
require_once dirname(__DIR__,2) . '/includes/functions.php';
erpGuard('marketplace_sync');
$pdo=getDB();
if($_SERVER['REQUEST_METHOD']==='POST'){
  try{
    $action=(string)($_POST['action']??'queue');
    if($action==='queue'){queueMarketplaceSync($pdo,trim((string)$_POST['marketplace']),trim((string)$_POST['entity_type']),(int)($_POST['entity_id']??0)?:null,trim((string)$_POST['direction']),json_decode((string)($_POST['payload_json']?:'{}'),true) ?: []);flash('success','Marketplace sync queued.');}
    elseif($action==='export'){createAccountingExportBatch($pdo,trim((string)$_POST['export_type']),trim((string)$_POST['date_from']),trim((string)$_POST['date_to']));flash('success','Accounting export batch created.');}
    elseif($action==='mark_done'){$pdo->prepare('UPDATE '.table('marketplace_sync_queue').' SET status="completed",last_attempt_at=NOW(),attempt_count=attempt_count+1 WHERE id=?')->execute([(int)$_POST['id']]);flash('success','Marketplace sync item completed.');}
  }catch(Throwable $e){recordSystemError($pdo,$e,['page'=>'marketplace-sync']);flash('error',$e->getMessage());}
  redirect(ADMIN_URL.'/erp/marketplace-sync.php');
}
$queue=$pdo->query('SELECT * FROM '.table('marketplace_sync_queue').' ORDER BY FIELD(status,"queued","failed","completed"),created_at DESC LIMIT 200')->fetchAll();
$exports=$pdo->query('SELECT * FROM '.table('accounting_export_batches').' ORDER BY created_at DESC LIMIT 100')->fetchAll();
include dirname(__DIR__).'/header.php';
?>
<div class="d-flex flex-wrap justify-content-between align-items-end gap-3 mb-4"><div><div class="erp-kicker">External Channel Sync</div><h2 class="h4 mb-1">Marketplace Sync & Accounting Export</h2><p class="text-secondary mb-0">Queue marketplace sync actions and prepare accounting export batches for external systems.</p></div></div>
<div class="row g-4"><div class="col-xl-4"><form method="post" class="card-admin p-4 mb-4"><input type="hidden" name="action" value="queue"><h2 class="h5 mb-3">Queue Marketplace Sync</h2><select class="form-select mb-2" name="marketplace"><option>Noon</option><option>Amazon</option><option>WooCommerce</option><option>eBay</option><option>Custom</option></select><select class="form-select mb-2" name="entity_type"><option>product</option><option>order</option><option>inventory</option><option>price</option></select><input class="form-control mb-2" type="number" name="entity_id" placeholder="Entity ID"><select class="form-select mb-2" name="direction"><option>outbound</option><option>inbound</option></select><textarea class="form-control mb-3" name="payload_json" rows="3">{}</textarea><button class="btn btn-brand w-100">Queue Sync</button></form><form method="post" class="card-admin p-4"><input type="hidden" name="action" value="export"><h2 class="h5 mb-3">Accounting Export</h2><select class="form-select mb-2" name="export_type"><option>journal_entries</option><option>invoices</option><option>payments</option><option>tax</option></select><input class="form-control mb-2" type="date" name="date_from" value="<?php echo date('Y-m-01'); ?>"><input class="form-control mb-3" type="date" name="date_to" value="<?php echo date('Y-m-d'); ?>"><button class="btn btn-outline-primary w-100">Create Export</button></form></div><div class="col-xl-8"><div class="table-wrap table-responsive mb-4"><h2 class="h5 mb-3">Sync Queue</h2><table class="table"><thead><tr><th>Queue</th><th>Marketplace</th><th>Entity</th><th>Status</th><th></th></tr></thead><tbody><?php foreach($queue as $q): ?><tr><td><strong><?php echo esc($q['queue_number']); ?></strong><div class="small text-secondary"><?php echo esc($q['direction'].' · '.$q['created_at']); ?></div></td><td><?php echo esc($q['marketplace']); ?></td><td><?php echo esc($q['entity_type'].' #'.$q['entity_id']); ?></td><td><span class="badge bg-<?php echo esc(statusTone($q['status'])); ?>"><?php echo esc($q['status']); ?></span></td><td><?php if($q['status']!=='completed'): ?><form method="post"><input type="hidden" name="action" value="mark_done"><input type="hidden" name="id" value="<?php echo (int)$q['id']; ?>"><button class="btn btn-sm btn-success">Done</button></form><?php endif; ?></td></tr><?php endforeach; ?></tbody></table></div><div class="table-wrap table-responsive"><h2 class="h5 mb-3">Accounting Exports</h2><table class="table"><thead><tr><th>Batch</th><th>Type</th><th>Period</th><th>Rows</th><th>Status</th></tr></thead><tbody><?php foreach($exports as $e): ?><tr><td><strong><?php echo esc($e['batch_number']); ?></strong><div class="small text-secondary"><?php echo esc($e['file_name']); ?></div></td><td><?php echo esc($e['export_type']); ?></td><td><?php echo esc($e['date_from'].' → '.$e['date_to']); ?></td><td><?php echo (int)$e['row_count']; ?></td><td><span class="badge bg-<?php echo esc(statusTone($e['status'])); ?>"><?php echo esc($e['status']); ?></span></td></tr><?php endforeach; ?></tbody></table></div></div></div>
<?php include dirname(__DIR__).'/footer.php'; ?>